// Extraer los resultados de Outscraper y guardar contexto del webhook
const webhookData = $('Webhook').first().json;
const outscraper = $input.first().json;

let businesses = [];
if (outscraper.data && Array.isArray(outscraper.data) && outscraper.data.length > 0) {
  businesses = Array.isArray(outscraper.data[0]) ? outscraper.data[0] : outscraper.data;
}

const results = businesses.map(biz => ({
  json: {
    name: biz.name || '',
    full_address: biz.full_address || '',
    phone: biz.phone || '',
    site: biz.site || '',
    email_1: biz.email_1 || biz.email_2 || '',
    rating: biz.rating || 0,
    reviews: biz.reviews || 0,
    category: biz.category || '',
    city: biz.city || webhookData.city || '',
    state: biz.state || webhookData.province || '',
    callback_url: webhookData.callback_url,
    progress_url: webhookData.progress_url,
    api_key: webhookData.api_key
  }
}));

return results.length > 0 ? results : [{ json: { error: 'No results', callback_url: webhookData.callback_url } }];

// Combinar datos originales + scoring de Dify
const items = $input.all();
const results = [];

for (const item of items) {
  const raw = item.json;
  let difyResult = {};

  try {
    // workflows/run devuelve data.outputs.result
    let answer = '';
    if (raw.data && raw.data.outputs && raw.data.outputs.result) {
      answer = raw.data.outputs.result;
    } else if (raw.answer) {
      answer = raw.answer;
    } else if (raw.text) {
      answer = raw.text;
    }
    const jsonMatch = answer.match(/\{[\s\S]*\}/);
    if (jsonMatch) {
      difyResult = JSON.parse(jsonMatch[0]);
    }
  } catch(e) {
    difyResult = {
      ai_score: 50,
      quality_level: 'average',
      recommendation: 'Clasificacion automatica no disponible',
      normalized_category: raw.category || '',
      recommended_first_line: ''
    };
  }

  // Recuperar datos originales del batch context
  const batchItems = $('Lotes de 3').all();
  const batchItem = batchItems.length > 0 ? batchItems[batchItems.length - 1].json : raw;

  results.push({
    json: {
      business_name: batchItem.name || raw.name || '',
      raw_category: batchItem.category || raw.category || '',
      normalized_category: difyResult.normalized_category || batchItem.category || '',
      province: batchItem.state || raw.state || '',
      city: batchItem.city || raw.city || '',
      website: batchItem.site || raw.site || '',
      email: batchItem.email_1 || raw.email_1 || '',
      phone: batchItem.phone || raw.phone || '',
      address: batchItem.full_address || raw.full_address || '',
      rating: batchItem.rating || raw.rating || 0,
      reviews_count: batchItem.reviews || raw.reviews || 0,
      ai_score: parseInt(difyResult.ai_score) || 50,
      quality_level: difyResult.quality_level || 'average',
      recommendation: difyResult.recommendation || '',
      recommended_first_line: difyResult.recommended_first_line || '',
      callback_url: batchItem.callback_url || raw.callback_url || '',
      progress_url: batchItem.progress_url || raw.progress_url || '',
      api_key: batchItem.api_key || raw.api_key || ''
    }
  });
}

return results;

// Agrupar todos los leads y enviar al callback de Spectra Flow
const allLeads = $input.all().map(i => {
  const d = i.json;
  return {
    business_name: d.business_name,
    raw_category: d.raw_category,
    normalized_category: d.normalized_category,
    province: d.province,
    city: d.city,
    website: d.website,
    email: d.email,
    phone: d.phone,
    address: d.address,
    rating: d.rating,
    reviews_count: d.reviews_count,
    ai_score: d.ai_score,
    quality_level: d.quality_level,
    recommendation: d.recommendation,
    recommended_first_line: d.recommended_first_line
  };
});

const first = $input.first().json;

return [{
  json: {
    leads: allLeads,
    raw_count: allLeads.length,
    callback_url: first.callback_url,
    api_key: first.api_key
  }
}];

// Flatten webhook body to root level
const body = $input.first().json.body || $input.first().json;
return [{ json: { ...body } }];
